const LAND_GOOD_START_X: u16 = 2;
const LAND_MARGINAL_START_X: u32 = 12;
const LAND_MARGINAL_SPACING: u32 = 6;
const LAND_GOOD_TO_MARGINAL_GAP: u32 = 4;
